import { useSelector } from 'react-redux';
import { selectUserProfile, selectUserSettings } from '../store/workspaceSlice';

export function WorkspaceHeader() {
  const profile = useSelector(selectUserProfile);
  const settings = useSelector(selectUserSettings);

  return (
    <header className="workspace-header">
      <h1>Workspace</h1>
      {profile && (
        <div className="user-info">
          <span>{profile.name}</span>
          <span className="role-badge">{profile.role}</span>
        </div>
      )}
      <span className="theme-indicator">{settings.theme}</span>
    </header>
  );
}

import { useSelector } from 'react-redux';
import { selectItems, selectItemCount } from '../store/workspaceSlice';

export function ItemList() {
  const items = useSelector(selectItems);
  const count = useSelector(selectItemCount);

  return (
    <div className="item-list">
      <h2>Items ({count})</h2>
      <ul>
        {items.map(item => (
          <li key={item.id}>
            <span className="item-title">{item.title}</span>
            <span className="item-type">{item.type}</span>
          </li>
        ))}
      </ul>
    </div>
  );
}

import { useSelector, useDispatch } from 'react-redux';
import { selectUserSettings } from '../store/workspaceSlice';

export function SettingsPanel() {
  const settings = useSelector(selectUserSettings);
  const dispatch = useDispatch();

  return (
    <div className="settings-panel">
      <h3>Settings</h3>
      <label>
        Theme: {settings.theme}
        <select value={settings.theme}>
          <option value="light">Light</option>
          <option value="dark">Dark</option>
          <option value="system">System</option>
        </select>
      </label>
      <label>
        <input type="checkbox" checked={settings.notifications} />
        Notifications
      </label>
    </div>
  );
}

import { useSelector } from 'react-redux';
import { selectSelectedItem, selectItems } from '../store/workspaceSlice';

export function ItemDetail() {
  const selectedItem = useSelector(selectSelectedItem);
  const allItems = useSelector(selectItems);

  if (!selectedItem) return <div>Select an item</div>;

  const relatedItems = allItems.filter(
    item => item.type === selectedItem.type && item.id !== selectedItem.id
  );

  return (
    <div className="item-detail">
      <h2>{selectedItem.title}</h2>
      <p>Type: {selectedItem.type}</p>
      <p>Updated: {selectedItem.updatedAt}</p>
      <h4>Related ({relatedItems.length})</h4>
    </div>
  );
}

