import { useState } from 'react';
import { useFormValidation } from '../hooks/useFormValidation';
import { registrationRules } from '../validation/registrationRules';

export function RegistrationForm() {
  const [values, setValues] = useState({ email: '', password: '', name: '' });
  const { errors, valid, dirty, validateField, validateAll, reset, firstError } =
    useFormValidation(registrationRules);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (validateAll(values)) {
      // submit
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      <input
        value={values.email}
        onChange={e => {
          setValues(v => ({ ...v, email: e.target.value }));
          validateField('email', e.target.value, values);
        }}
      />
      {firstError('email') && <span className="error">{firstError('email')}</span>}
      <button disabled={!valid || !dirty}>Register</button>
    </form>
  );
}

import { useState } from 'react';
import { useFormValidation } from '../hooks/useFormValidation';
import { contactRules } from '../validation/contactRules';

export function ContactForm() {
  const [values, setValues] = useState({ name: '', email: '', message: '' });
  const { errors, valid, reset, touch, isTouched, validateAll } =
    useFormValidation(contactRules, true, true);

  const handleBlur = (field: string) => {
    touch(field);
  };

  const handleSubmit = () => {
    if (validateAll(values)) {
      // submit and reset
      reset();
    }
  };

  return (
    <div>
      <input
        value={values.name}
        onBlur={() => handleBlur('name')}
        onChange={e => setValues(v => ({ ...v, name: e.target.value }))}
      />
      {isTouched('name') && errors.name?.length > 0 && (
        <span className="error">{errors.name[0]}</span>
      )}
      <button disabled={!valid} onClick={handleSubmit}>Send</button>
    </div>
  );
}

