import { useTheme } from '../theme/ThemeProvider';

export function PrimaryButton({ children, onClick }: { children: React.ReactNode; onClick: () => void }) {
  const theme = useTheme();

  return (
    <button
      onClick={onClick}
      style={{
        backgroundColor: theme.colors.primary,
        color: '#fff',
        padding: `${theme.spacing.sm} ${theme.spacing.md}`,
        border: 'none',
        borderRadius: theme.radii.medium,
        fontFamily: theme.fonts.body,
        cursor: 'pointer',
      }}
    >
      {children}
    </button>
  );
}

import { useTheme } from '../theme/ThemeProvider';

export function Card({ children, title }: { children: React.ReactNode; title?: string }) {
  const theme = useTheme();

  return (
    <div
      style={{
        backgroundColor: theme.colors.surface,
        boxShadow: theme.shadows.card,
        borderRadius: theme.radii.large,
        padding: theme.spacing.lg,
      }}
    >
      {title && <h3 style={{ fontFamily: theme.fonts.heading }}>{title}</h3>}
      {children}
    </div>
  );
}

import { useTheme } from '../theme/ThemeProvider';

export function ResponsiveGrid({ children }: { children: React.ReactNode }) {
  const theme = useTheme();

  return (
    <div
      style={{
        display: 'grid',
        gap: theme.spacing.md,
        padding: theme.spacing.lg,
      }}
      className="responsive-grid"
    >
      <style>{`
        @media (min-width: ${theme.breakpoints.tablet}) {
          .responsive-grid { grid-template-columns: repeat(2, 1fr); }
        }
        @media (min-width: ${theme.breakpoints.desktop}) {
          .responsive-grid { grid-template-columns: repeat(3, 1fr); }
        }
      `}</style>
      {children}
    </div>
  );
}

import { useTheme } from '../theme/ThemeProvider';

export function DropdownMenu({ items, isOpen }: { items: string[]; isOpen: boolean }) {
  const theme = useTheme();

  if (!isOpen) return null;

  return (
    <ul
      style={{
        position: 'absolute',
        backgroundColor: theme.colors.surface,
        boxShadow: theme.shadows.dropdown,
        borderRadius: theme.radii.medium,
        padding: `${theme.spacing.xs} 0`,
        listStyle: 'none',
        minWidth: '200px',
      }}
    >
      {items.map(item => (
        <li
          key={item}
          style={{
            padding: `${theme.spacing.xs} ${theme.spacing.sm}`,
            fontFamily: theme.fonts.body,
          }}
        >
          {item}
        </li>
      ))}
    </ul>
  );
}

import { useTheme } from '../theme/ThemeProvider';

export function FormField({ label, error, children }: { label: string; error?: string; children: React.ReactNode }) {
  const theme = useTheme();

  return (
    <div style={{ marginBottom: theme.spacing.md }}>
      <label
        style={{
          display: 'block',
          marginBottom: theme.spacing.xs,
          fontFamily: theme.fonts.body,
          color: theme.colors.text,
        }}
      >
        {label}
      </label>
      {children}
      {error && (
        <span
          style={{
            color: theme.colors.error,
            fontSize: '12px',
            marginTop: theme.spacing.xs,
            fontFamily: theme.fonts.body,
          }}
        >
          {error}
        </span>
      )}
    </div>
  );
}

